const codes = {"Java": "<span class=\"kw\">interface</span> <span class=\"cl\">JsonService</span> {\n  <span class=\"cl\">String</span> <span class=\"fn\">toJson</span>(<span class=\"cl\">Object</span> <span class=\"dc\">obj</span>);\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">LegacyXml</span> {\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">serialize</span>(<span class=\"cl\">Object</span> <span class=\"dc\">obj</span>) {\n    <span class=\"kw\">return</span> <span class=\"st\">\"&lt;obj&gt;\"</span> + <span class=\"dc\">obj</span> + <span class=\"st\">\"&lt;/obj&gt;\"</span>;\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">XmlToJsonAdapter</span> <span class=\"kw\">implements</span> <span class=\"cl\">JsonService</span> {\n  <span class=\"kw\">private final</span> <span class=\"cl\">LegacyXml</span> <span class=\"dc\">xml</span>;\n\n  <span class=\"fn\">XmlToJsonAdapter</span>(<span class=\"cl\">LegacyXml</span> <span class=\"dc\">x</span>) { <span class=\"dc\">this</span>.<span class=\"dc\">xml</span> = <span class=\"dc\">x</span>; }\n\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">toJson</span>(<span class=\"cl\">Object</span> <span class=\"dc\">obj</span>) {\n    <span class=\"kw\">return</span> <span class=\"st\">\"{{\\\"v\\\":\\\"\"</span> + <span class=\"dc\">xml</span>.<span class=\"fn\">serialize</span>(<span class=\"dc\">obj</span>) + <span class=\"st\">\"\\\"}}\"</span>;\n  }\n}", "CSharp": "<span class=\"kw\">public interface</span> <span class=\"cl\">IJson</span> {\n  <span class=\"kw\">string</span> <span class=\"fn\">ToJson</span>(<span class=\"kw\">object</span> <span class=\"dc\">obj</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">LegacyXml</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">Serialize</span>(<span class=\"kw\">object</span> <span class=\"dc\">obj</span>) =&gt;\n    <span class=\"st\">$\"&lt;obj&gt;{{obj}}&lt;/obj&gt;\"</span>;\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">XmlToJsonAdapter</span>(<span class=\"cl\">LegacyXml</span> <span class=\"dc\">xml</span>) : <span class=\"cl\">IJson</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">ToJson</span>(<span class=\"kw\">object</span> <span class=\"dc\">obj</span>) =&gt;\n    <span class=\"st\">$\"{{\\\"v\\\":\\\"{xml.Serialize(obj)}\\\"}}\"</span>;\n}", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">LegacyXml</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">serialize</span>(<span class=\"dc\">self</span>, <span class=\"dc\">obj</span>) -&gt; <span class=\"kw\">str</span>:\n    <span class=\"kw\">return</span> <span class=\"st\">f\"&lt;obj&gt;{{obj}}&lt;/obj&gt;\"</span>\n\n\n<span class=\"kw\">class</span> <span class=\"cl\">XmlToJsonAdapter</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>, <span class=\"dc\">xml</span>: <span class=\"cl\">LegacyXml</span>):\n    <span class=\"dc\">self.xml</span> = <span class=\"dc\">xml</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">to_json</span>(<span class=\"dc\">self</span>, <span class=\"dc\">obj</span>) -&gt; <span class=\"kw\">str</span>:\n    <span class=\"kw\">return</span> <span class=\"st\">f'{{\"v\":\"{self.xml.serialize(obj)}\"}}'</span>\n\n\n<span class=\"dc\">adapter</span> = <span class=\"cl\">XmlToJsonAdapter</span>(<span class=\"cl\">LegacyXml</span>())\n<span class=\"fn\">print</span>(<span class=\"dc\">adapter</span>.<span class=\"fn\">to_json</span>(<span class=\"st\">\"user\"</span>))", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">LegacyXml</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">serialize</span>(<span class=\"dc\">obj</span>) = <span class=\"st\">\"&lt;obj&gt;#{{obj}}&lt;/obj&gt;\"</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">XmlToJsonAdapter</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>(<span class=\"dc\">xml</span>) = <span class=\"dc\">@xml</span> = <span class=\"dc\">xml</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">to_json</span>(<span class=\"dc\">obj</span>)\n    <span class=\"st\">\"{{\\\"v\\\":\\\"#{{@xml.serialize(obj)}}\\\"}}\"</span>\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>"}

